def get_display_label(key: str) -> str:
    """Return the best display label for a platform/registry/language key."""
    return (
        PLATFORM_LABELS.get(key)
        or REGISTRY_LABELS.get(key)
        or LANGUAGE_LABELS.get(key)
        or key.title()
    )


@dataclass(frozen=True)
class RegistryTemplate:
    """A typed registry template definition.

    Each registry template defines one or more URL patterns and the values
    required to interpolate them.
    """

    templates: dict[str, str]
    required: tuple[str, ...] = ()
    optional: tuple[str, ...] = ()

    def get(self, key: str, default: str | None = None) -> str | None:
        """Return the template string for *key* or *default* if missing."""
        return self.templates.get(key, default)


