def validate_registry_template(registry: str, template_key: str = "default") -> None:
    """Validate that *registry* has a template identified by *template_key*.

    And that the template definition declares required placeholders.

    Raises ValueError on invalid input.
    """
    if registry not in REGISTRY_TEMPLATES:
        raise ValueError(f"unknown registry: {registry!r}")
    template = REGISTRY_TEMPLATES[registry]
    if template_key not in template.templates:
        raise ValueError(f"registry {registry!r} has no template {template_key!r}")


def format_registry_url(registry: str, *, template_key: str = "default", **values: object) -> str:
    """Format a registry URL for *registry* using named *values*.

    Example:
        format_registry_url("pypi", package="requests")
        -> "https://pypi.org/project/requests/"
    """
    if registry not in REGISTRY_TEMPLATES:
        raise ValueError(f"unknown registry: {registry!r}")
    template = REGISTRY_TEMPLATES[registry]
    if template_key in template.templates:
        tmpl = template.templates[template_key]
    else:
        tmpl = template.templates.get("default") or next(iter(template.templates.values()))

    missing = [r for r in template.required if r not in values or values.get(r) in (None, "")]
    if missing:
        raise ValueError(f"missing required values for registry {registry}: {', '.join(missing)}")

    if not isinstance(tmpl, str):  # pragma: no cover
        tmpl = str(tmpl)

    try:
        return tmpl.format(**values)
    except Exception as exc:  # pragma: no cover - defensive
        raise ValueError(f"failed to format template for {registry}: {exc}")


